function FadeIn({ children, delay = 0 }) {
  const [v, setV] = useState(false);
  useEffect(() => { const t = setTimeout(() => setV(true), delay); return () => clearTimeout(t); }, [delay]);
  return <div style={{ opacity: v ? 1 : 0, transform: v ? "translateY(0)" : "translateY(16px)", transition: "opacity 0.6s ease, transform 0.6s ease" }}>{children}</div>;
}

function BackBtn({ onClick, label = "Back" }) {
  const [h, setH] = useState(false);
  return (
    <button onClick={onClick} onMouseEnter={() => setH(true)} onMouseLeave={() => setH(false)}
      style={{ padding: "10px 20px", background: h ? colors.navy : colors.white, border: `1.5px solid ${colors.navy}`, borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: "pointer", color: h ? colors.white : colors.navy, display: "flex", alignItems: "center", gap: 6, transition: "all 0.2s ease" }}>
      <span style={{ fontSize: 16 }}>←</span> {label}
    </button>
  );
}

function NextBtn({ onClick, label = "Continue", gold = false, disabled = false }) {
  const bg = gold ? colors.gold : colors.navy;
  const fg = gold ? colors.navy : colors.white;
  return (
    <button onClick={onClick} disabled={disabled}
      style={{ padding: "10px 24px", background: disabled ? colors.gray300 : bg, color: disabled ? colors.gray500 : fg, border: "none", borderRadius: 8, fontSize: 13, fontWeight: 700, cursor: disabled ? "default" : "pointer", display: "flex", alignItems: "center", gap: 6, transition: "all 0.2s ease" }}>
      {label} <span style={{ fontSize: 16 }}>→</span>
    </button>
  );
}

function Nav({ back, next }) {
  return <div style={{ display: "flex", justifyContent: back ? "space-between" : "flex-end", marginTop: 32 }}>
    {back && <BackBtn onClick={back.onClick} label={back.label} />}
    {next && <NextBtn onClick={next.onClick} label={next.label} gold={next.gold} disabled={next.disabled} />}
  </div>;
}

function Sidebar({ currentPage, setCurrentPage, currentModule, open, onClose }) {
  const isMobile = useIsMobile();

  // Map nav keys to actual URLs
  const getHref = (key) => {
    if (key === "dashboard") return "/";
    if (key === "intro") return "/modules/introduction";
    if (key === "conclusion") return "/modules/commissioning";
    if (key.startsWith("module-")) {
      const id = parseInt(key.split("-")[1]);
      const mod = modules.find(m => m.id === id);
      if (mod) return `/modules/${mod.title.toLowerCase()}`;
    }
    return null;
  };

  const navItems = [
    { key: "dashboard", label: "Dashboard", icon: "⬡" },
    { key: "intro", label: "Introduction", icon: "◈" },
    ...modules.filter(m => m.id >= 1 && m.id <= 5).map(m => ({ key: `module-${m.id}`, label: `${m.id}. ${m.title}`, icon: m.icon, locked: false, completed: mockProgress.modulesCompleted.includes(m.id), active: mockProgress.modulesInProgress.includes(m.id) })),
    { key: "conclusion", label: "Commissioning", icon: "◉", locked: false },
    { key: "certificate", label: "Certificate", icon: "✦", locked: true },
  ];
  return (
    <>
      {/* Mobile overlay backdrop */}
      {isMobile && open && (
        <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 49 }} />
      )}
      <div style={{
        width: 260, minHeight: "100vh", background: colors.navy, borderRight: `1px solid ${colors.navyMid}`,
        flexShrink: 0, display: "flex", flexDirection: "column",
        ...(isMobile ? {
          position: "fixed", top: 0, left: 0, zIndex: 50, height: "100vh", overflowY: "auto",
          transform: open ? "translateX(0)" : "translateX(-100%)",
          transition: "transform 0.3s ease",
        } : {}),
      }}>
      <div style={{ padding: "20px 16px 16px", borderBottom: `1px solid ${colors.navyMid}` }}>
        <div style={{ background: colors.white, borderRadius: 8, padding: "10px 12px 8px", marginBottom: 10 }}>
          <img src={LOGO_SRC} alt="Awakening Destiny Global" style={{ width: "100%", height: "auto", display: "block" }} />
        </div>
        <div style={{ fontSize: 13, color: colors.white, fontWeight: 700, textAlign: "center" }}>5C Leadership Blueprint</div>
        <div style={{ fontSize: 11, color: colors.gray300, textAlign: "center", fontStyle: "italic" }}>From Design to Destiny</div>
      </div>
      <div style={{ padding: "12px 0", flex: 1, overflowY: "auto" }}>
        {navItems.map(item => {
          const act = currentPage === item.key, lk = item.locked, done = item.completed;
          const href = getHref(item.key);
          // Use <a> tag for external page navigation, div for in-app state
          const inner = (
            <>
              <span style={{ fontSize: 14, width: 22, textAlign: "center", color: done ? colors.gold : act ? colors.skyBlue : colors.gray300 }}>{done ? "✓" : lk ? "🔒" : item.icon}</span>
              <span style={{ fontSize: 13, fontWeight: act ? 600 : 400, color: act ? colors.white : colors.gray300 }}>{item.label}</span>
              {item.active && <span style={{ marginLeft: "auto", fontSize: 9, background: colors.skyBlue, color: colors.white, padding: "2px 6px", borderRadius: 10, fontWeight: 600 }}>ACTIVE</span>}
            </>
          );
          const sharedStyle = { padding: "10px 20px", display: "flex", alignItems: "center", gap: 10, background: act ? colors.navyLight : "transparent", borderLeft: act ? `3px solid ${colors.gold}` : "3px solid transparent", opacity: lk ? 0.35 : 1, transition: "all 0.2s ease", textDecoration: "none" };
          if (href && !lk) {
            return <a key={item.key} href={href} style={{ ...sharedStyle, cursor: "pointer" }}>{inner}</a>;
          }
          return (
            <div key={item.key} onClick={() => { if (!lk) { setCurrentPage(item.key); if (isMobile) onClose(); } }}
              style={{ ...sharedStyle, cursor: lk ? "default" : "pointer" }}
              onMouseEnter={e => { if (!lk && !act) e.currentTarget.style.background = colors.navyLight; }}
              onMouseLeave={e => { if (!act) e.currentTarget.style.background = "transparent"; }}>
              {inner}
            </div>
          );
        })}
      </div>
      <div style={{ padding: "16px 20px", borderTop: `1px solid ${colors.navyMid}` }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 32, height: 32, borderRadius: "50%", background: colors.royalBlue, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, fontWeight: 700, color: colors.white }}>WM</div>
          <div><div style={{ fontSize: 12, color: colors.white, fontWeight: 500 }}>Will Meier</div><div style={{ fontSize: 10, color: colors.gray500 }}>Participant</div></div>
        </div>
      </div>
      </div>
    </>
  );
}

function ProgressRing({ percent, size = 120, sw = 8 }) {
  const r = (size - sw) / 2, c = 2 * Math.PI * r;
  return <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
    <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={colors.navyMid} strokeWidth={sw} />
    <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={colors.gold} strokeWidth={sw} strokeDasharray={c} strokeDashoffset={c-(percent/100)*c} strokeLinecap="round" style={{ transition: "stroke-dashoffset 1.5s ease" }} />
  </svg>;
}

function ScoreBar({ label, pre, post, max = 60 }) {
  return <div style={{ marginBottom: 16 }}>
    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
      <span style={{ fontSize: 13, fontWeight: 600, color: colors.navy }}>{label}</span>
      <span style={{ fontSize: 12, color: colors.gray500 }}>{pre}/60 → {post ? `${post}/60` : "—"}{post && <span style={{ color: "#16a34a", fontWeight: 600, marginLeft: 6 }}>+{post-pre}</span>}</span>
    </div>
    <div style={{ height: 8, background: colors.gray200, borderRadius: 4, position: "relative", overflow: "hidden" }}>
      <div style={{ position: "absolute", height: "100%", borderRadius: 4, background: colors.gray300, width: `${(pre/max)*100}%` }} />
      {post && <div style={{ position: "absolute", height: "100%", borderRadius: 4, background: `linear-gradient(90deg, ${colors.skyBlue}, ${colors.royalBlue})`, width: `${(post/max)*100}%` }} />}
    </div>
    <div style={{ display: "flex", gap: 12, marginTop: 4 }}><span style={{ fontSize: 10, color: colors.gray500 }}>■ Pre</span>{post && <span style={{ fontSize: 10, color: colors.royalBlue }}>■ Post</span>}</div>
  </div>;
}

